        //   "collateralToken":array(
        //       "address":"0x833589fCD6eDb6E08f4c7C32D4f71b54bdA02913",
        //       "decimals":"6",
        //       "symbol":"USDC"
        //   ),
        //   "title":"💎 Trump out before 2027?",
