        //   "volume":"290091252",
        //   "volumeFormatted":"290.091252",
        //   "tokens":array(
        //       "yes":"56154308742753982686710750162015444986563701968079760676518531584453506363044",
        //       "no":"32572248812801208874557774576516861470423415416073401354576860825663488568217"
        //   ),
        //   "prices":array(
        //       0.164,
        //       0.836
        //   ),
        //   "isOther":false,
        //   "isRewardable":true,
        //   "slug":"trump-out-as-president-before-2027-1768933068297",
        //   "tradeType":"clob",
        //   "venue":array(
        //       "exchange":"0x05c748E2f4DcDe0ec9Fa8DDc40DE6b867f923fa5",
        //       "adapter":null
        //   ),
        //   "marketType":"single",
        //   "priorityIndex":"0",
        //   "winningOutcomeIndex":null,
        //   "metadata":array(
        //       "fee":true,
        //       "isBannered":false,
        //       "isPolyArbitrage":true
        //   ),
        //   "trends":{
        //       "hourly":array(
        //           "value":"3",
        //           "rank":"395"
        //       }
        //   ),
        //   "settings":array(
        //       "minSize":"100000000",
        //       "maxSpread":"0.035",
        //       "dailyReward":"5",
        //       "rewardsEpoch":"0.003472222222222222",
        //       "c":"3",
        //       "rebateRate":"0"
        //   ),
        //   "imageUrl":"https://cdn.limitless.exchange/markets-logo/36814/9daba01d-6bcd-4a2c-9187-f4264b7191da.png",
        //   "logo":"https://cdn.limitless.exchange/markets-logo/36814/9daba01d-6bcd-4a2c-9187-f4264b7191da.png"
        // }
        //
        $slug = $this->safe_string($raw, 'slug');
        $address = $this->safe_string($raw, 'address', $slug);
        $groupId = $this->safe_string($raw, 'groupId', $slug);
        $tokens = $this->safe_value($raw, 'tokens', array());
        $active = $this->safe_bool($raw, 'active', true);
        $endDate = $this->safe_string($raw, 'deadline', $this->safe_string($raw, 'expiresAt'));
        $volume24h = $this->safe_number($raw, 'volume24h');
        // resolution => $winningOutcomeIndex is null until the market resolves, then the winning outcome index
        $winningOutcomeIndex = $this->safe_integer($raw, 'winningOutcomeIndex');
        $marketResolved = ($winningOutcomeIndex !== null);
        $resolvedOutcome = null;
        $marketSymbol = $this->slug_to_market_symbol($groupId, $slug);
        // amount $precision comes from the collateral token decimals (USDC, 6); limitless does not
        // expose a price tick, so 0.001 is the platform convention
        $collateralToken = $this->safe_dict($raw, 'collateralToken', array());
        $collateralDecimals = $this->safe_integer($collateralToken, 'decimals', $this->safe_integer($this->options, 'usdcDecimals', 6));
        $precision = array(
            'amount' => (string) $this->parse_number($this->parse_precision($collateralDecimals)),
            'price' => 0.001,
        );
        $outcomes = array();
        $tokenEntries = is_array($tokens) ? array_keys($tokens) : array();
        for ($i = 0; $i < count($tokenEntries); $i++) {
            $outcomeLabel = $tokenEntries[$i];
            $tokenData = $tokens[$outcomeLabel];
            $tokenId = $tokenData;
            $outcomeHandle = $this->slug_to_outcome_symbol($groupId, $slug, $outcomeLabel);
            $winner = null;
            $settleFraction = null;
            if ($marketResolved) {
                $winner = ($i === $winningOutcomeIndex);
                $settleFraction = $winner ? 1 : 0;
                if ($winner) {
                    $resolvedOutcome = $outcomeHandle;
                }
            }
            $outcomes[] = array(
                'outcome' => $outcomeHandle,
                'outcomeId' => $tokenId,
                'market' => $marketSymbol,
                'label' => $outcomeLabel,
                'active' => $active,
                'winner' => $winner,
                'settleFraction' => $settleFraction,
                'precision' => $precision,
                'info' => array(
                    'slug' => $slug,
                    'address' => $address,
                    'outcomeLabel' => $outcomeLabel,
                    'tokenId' => $tokenId,
                    'volume24h' => $volume24h,
                ),
            );
        }
        $outcomesLength = count($outcomes);
        return array(
            'id' => $slug,
            'symbol' => $marketSymbol,
            'market' => $marketSymbol,
            'marketType' => ($outcomesLength > 2) ? 'categorical' : 'binary',
            'executionModel' => 'clob',
            'collateral' => 'USDC',
            'base' => $slug,
            'quote' => 'USDC',
            'settle' => null,
            'baseId' => $slug,
            'quoteId' => 'USDC',
            'settleId' => null,
            'type' => 'prediction',
            'spot' => false,
            'margin' => false,
            'swap' => false,
            'future' => false,
            'option' => false,
            'prediction' => true,
            'active' => $active,
            'resolved' => $marketResolved,
            'resolvedOutcome' => $resolvedOutcome,
            'contract' => false,
            'linear' => null,
            'inverse' => null,
            'contractSize' => null,
            'expiry' => $endDate ? $this->parse8601($endDate) : null,
            'expiryDatetime' => $endDate,
            'strike' => null,
            'optionType' => null,
            'taker' => 0.02,
            'maker' => 0.02,
            'percentage' => true,
            'tierBased' => false,
            'feeSide' => 'get',
            'precision' => $precision,
            'limits' => array(
                'leverage' => array( 'min' => 1, 'max' => 1 ),
                'amount' => array( 'min' => 0, 'max' => null ),
                'price' => array( 'min' => 0.001, 'max' => 0.999 ),
                'cost' => array( 'min' => null, 'max' => null ),
            ),
            'outcomes' => $outcomes,
            'info' => $this->extend($raw, array(
                'slug' => $slug,
                'address' => $address,
                'volume24h' => $volume24h,
            )),
            'created' => null,
        );
    }

    public function fetch_event(string $id, $params = array()): PromiseInterface {
        return Async\async(function () use ($id, $params) {
            /**
             * fetches a single prediction-market $event by its market slug or address
             *
             * @see https://docs.limitless.exchange/api-reference/markets/get-market
             *
             * @param {string} $id the market slug or address
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a [prediction $event structure](https://docs.ccxt.com/#/?$id=prediction-$event-structure)
             */
            $request = array( 'addressOrSlug' => $id );
            $response = Async\await($this->limitlessPublicGetMarketsAddressOrSlug($this->extend($request, $params)));
            // the single-market endpoint returns one raw market (no `markets` array like the grouped
            // listing), so wrap it for parseEvent — its loop then parses this market into the $event
            $wrapped = $this->extend($response, array( 'markets' => array( $response ) ));
            $event = $this->parse_event($wrapped);
            $this->index_event_outcomes($event);
            return $event;
        })();
    }

