    public function get_position_from_clob_entry(string $label, ?array $entry = null) {
        if ($entry === null) {
            return null;
        }
        $tokensBalance = $this->safe_dict($entry, 'tokensBalance');
        $contracts = $this->omit_zero($this->safe_string($tokensBalance, $label));
        if ($contracts === null) {
            return null;
        }
        $positions = $this->safe_dict($entry, 'positions');
        $position = $this->safe_dict($positions, $label);
        $rawMarket = $this->safe_dict($entry, 'market');
        $slug = $this->safe_string($rawMarket, 'slug');
        $outcomeObj = $this->get_outcome_by_slug_and_label($slug, $label);
        $parsed = $this->parse_position($position, $outcomeObj);
        $parsed['contracts'] = $this->parse_number($this->apply_scale($contracts));
        $latestTrade = $this->safe_dict($entry, 'latestTrade');
        $key = 'latestYesPrice';
        if ($label === 'no') {
            $key = 'latestNoPrice';
        }
        $parsed['markPrice'] = $this->safe_number($latestTrade, $key);
        $parsed['info'] = $entry;
        return $this->safe_prediction_position($parsed);
    }

    public function parse_position(array $position, ?array $market = null): array {
        /**
         * @ignore
         * parses a raw limitless portfolio $position into a unified $position object
         * @param {array} $position the raw $position object
         * @param {array} [$market] the outcome object the $position belongs to
         * @return {array} a [$position structure](https://docs.ccxt.com/#/?id=$position-structure)
         */
        //
        //     {
        //         "cost" => "995720",
        //         "fillPrice" => "991000",
        //         "marketValue" => "999919",
        //         "realisedPnl" => "0",
        //         "unrealizedPnl" => "0"
        //     }
        //
        $outcomeSymbol = $this->safe_string($market, 'outcome');
        $notional = $this->apply_scale($this->safe_string($position, 'marketValue'));
        $unrealizedPnl = $this->apply_scale($this->safe_string($position, 'unrealizedPnl'));
        $realizedPnl = $this->apply_scale($this->safe_string($position, 'realisedPnl'));
        $collateral = $this->apply_scale($this->safe_string($position, 'cost'));
        $entryPrice = $this->apply_scale($this->safe_string($position, 'fillPrice'));
        return array(
            'id' => null,
            'outcome' => $outcomeSymbol,
            'outcomeId' => $this->safe_string($market, 'outcomeId'),
            'label' => $this->safe_string($market, 'label'),
            'market' => $this->safe_string($market, 'market'),
            'timestamp' => null,
            'datetime' => null,
            'contracts' => null,
            'contractSize' => 1,
            'side' => 'long',
            'notional' => $this->parse_number($notional),
            'leverage' => 1,
            'unrealizedPnl' => $this->parse_number($unrealizedPnl),
            'realizedPnl' => $this->parse_number($realizedPnl),
            'collateral' => $this->parse_number($collateral),
            'entryPrice' => $this->parse_number($entryPrice),
            'markPrice' => null,
            'liquidationPrice' => null,
            'hedged' => false,
            'maintenanceMargin' => null,
            'maintenanceMarginPercentage' => null,
            'initialMargin' => null,
            'initialMarginPercentage' => null,
            'marginRatio' => null,
            'marginMode' => 'cross',
            'marginType' => 'cross',
            'percentage' => null,
            'info' => $position,
        );
    }

    public function fetch_events(array $params = array()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * fetches prediction-market events matching the given search terms (or the most active markets, capped, when omitted) and caches their markets and outcomes on the instance
             *
             * @see https://docs.limitless.exchange/api-reference/markets/search
             *
             * @param {array} [$params] extra exchange-specific parameters
             * @param {string} [$params->query] a single search term; when omitted, an eventId/slug does a direct lookup and any other scope (tags) pages the active-markets listing
             * @param {string[]} [$params->queries] multiple search terms (alternative to query)
             * @param {string} [$params->eventId] direct lookup by market address or slug
             * @param {int} [$params->limit] maximum number of markets per query, defaults to 50
             * @return {array[]} an array of event structures
             */
            $this->require_event_query($params);
            $queries = $this->parse_search_queries($params);
            $queriesLength = count($queries);
            $rest = $this->omit($params, array( 'query', 'queries', 'limit', 'sort', 'searchIn', 'eventId', 'slug', 'status' ));
            $eventId = $this->safe_string_2($params, 'eventId', 'slug');
            // always fetch fresh from the API (never serve the possibly-cold cache) => a query searches, an
            // eventId/slug does a direct lookup, and any other scope (tags) pages the active-markets listing
            $rawMarkets = array();
            if ($queriesLength > 0) {
                $requestedLimit = $this->safe_integer($params, 'limit', 50);
                // the search endpoint rejects $limit > 50 - cap the per-query request
                $limit = min($requestedLimit, 50);
                $seen = array();
                for ($i = 0; $i < count($queries); $i++) {
                    $q = $queries[$i];
                    $response = Async\await($this->limitlessPublicGetMarketsSearch($this->extend(array(
                        'query' => $q,
                        'limit' => $limit,
                    ), $rest)));
                    $found = $this->safe_list($response, 'markets', array());
                    for ($j = 0; $j < count($found); $j++) {
                        $raw = $found[$j];
                        $rawSlug = $this->safe_string($raw, 'slug');
                        if ($rawSlug && !(is_array($seen) && array_key_exists($rawSlug, $seen))) {
                            $seen[$rawSlug] = true;
                            $rawMarkets[] = $raw;
                        }
                    }
                }
            } elseif ($eventId !== null) {
                $response = Async\await($this->limitlessPublicGetMarketsAddressOrSlug($this->extend(array( 'addressOrSlug' => $eventId ), $rest)));
                $rawMarkets[] = $response;
            } else {
                $listRaw = Async\await($this->fetch_raw_active_markets($params));
                $listRawLength = count($listRaw);
                for ($i = 0; $i < $listRawLength; $i++) {
                    $rawMarkets[] = $listRaw[$i];
                }
            }
            if (!$this->events) {
                $this->events = array();
            }
            if (!$this->markets) {
                $this->markets = $this->create_safe_dictionary();
            }
            $eventGroups = array();
            $rawMarketsLength = count($rawMarkets);
            for ($i = 0; $i < $rawMarketsLength; $i++) {
                $raw = $rawMarkets[$i];
                $groupId = $this->safe_string($raw, 'groupId', $this->safe_string($raw, 'slug'));
                $eventKey = $groupId ? $this->shorten_slug($groupId) : null;
                $m = $this->parse_market($raw);
                $this->markets[$m['symbol']] = $m;
                if ($eventKey) {
                    if (!(is_array($eventGroups) && array_key_exists($eventKey, $eventGroups))) {
                        $eventGroups[$eventKey] = array( 'groupId' => $groupId, 'title' => $this->safe_string($raw, 'title', $groupId), 'raw' => $raw, 'markets' => array() );
                    }
                    $eventGroup = $eventGroups[$eventKey];
                    $eventGroup['markets'][] = $m;
                }
            }
            $result = array();
            $eventKeys = is_array($eventGroups) ? array_keys($eventGroups) : array();
            $eventKeysLength = count($eventKeys);
            for ($i = 0; $i < $eventKeysLength; $i++) {
                $g = $eventGroups[$eventKeys[$i]];
                $ev = $this->parse_event($g);
                $result[] = $ev;
            }
            // setEvents keys events by id/slug/handle; populateOutcomes rebuilds the outcome cache
            $this->set_events($result);
            $this->populate_outcomes();
            return $this->apply_event_fetch_params($result, $params, $queries);
        })();
    }

    public function fetch_raw_active_markets($params = array()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * @ignore
             * pages the active-markets listing, bounded by limit (or options.fetchMarketsLimit)
             * @param {array} [$params] extra exchange-specific parameters
             * @param {int} [$params->limit] max number of raw markets to collect
             * @return {array[]} raw limitless market objects
             */
            $maxMarkets = $this->safe_integer($params, 'limit', $this->safe_integer($this->options, 'fetchMarketsLimit', 1000));
            $pageSize = $this->safe_integer($this->options, 'marketsPageSize', 25);
            $rest = $this->omit($params, array( 'query', 'queries', 'limit', 'sort', 'searchIn', 'eventId', 'slug', 'status', 'tags' ));
            $allRaw = array();
            $page = 1;
            $collected = 0;
            while (true) {
                $request = array( 'page' => $page, 'limit' => $pageSize );
                $response = Async\await($this->limitlessPublicGetMarketsActive($this->extend($request, $rest)));
                $data = $this->safe_list($response, 'data', array());
                $dataLength = count($data);
                if ($dataLength === 0) {
                    break;
                }
                for ($i = 0; $i < $dataLength; $i++) {
                    if ($collected < $maxMarkets) {
                        $allRaw[] = $data[$i];
                        $collected = $this->sum($collected, 1);
                    }
                }
                $page = $this->sum($page, 1);
                if ($dataLength < $pageSize || $collected >= $maxMarkets) {
                    break;
                }
            }
            return $allRaw;
        })();
    }

    public function sign(mixed $path, mixed $section = 'limitless', $method = 'GET', $params = array(), mixed $headers = null, mixed $body = null) {
        /**
         * @ignore
         * builds the request URL and attaches the lmts authentication $headers for private endpoints
         * @param {string} $path the endpoint $path
         * @param {string|string[]} [$section] the api group and $access level
         * @param {string} [$method] HTTP $method
         * @param {array} [$params] request parameters
         * @param {array} [$headers] request $headers
         * @param {array} [$body] request $body
         * @return {array} a dictionary with $url, $method, $body and $headers
         */
        $apiGroup = gettype($section) === 'string' ? $section : $section[0];
        $access = gettype($section) === 'string' ? 'public' : $section[1];
        $baseUrls = $this->urls['api'];
        $baseUrl = $this->safe_string($baseUrls, $apiGroup, $baseUrls['limitless']);
        $url = '/' . $this->implode_params($path, $params);
        $query = $this->omit($params, $this->extract_params($path));
        $querystring = $this->urlencode_with_array_repeat($query);
        if ($method === 'GET' && $querystring) {
            $url .= '?' . $querystring;
        }
        if ($access === 'private') {
            $bodyString = '';
            if ($headers === null) {
                $headers = array();
            }
            if ($method === 'POST' && $querystring) {
                $bodyString = $this->json($query);
                $body = $bodyString;
                $headerDefaults = ($headers !== null) ? $headers : array();
                $headers = $this->extend(array(
                    'Accept' => 'application/json',
                    'Content-Type' => 'application/json',
                ), $headerDefaults);
            }
            $this->check_required_credentials();
            $timestamp = $this->iso8601($this->milliseconds());
            $newline = "\n"; // eslint-disable-line quotes
            $payload = $timestamp . $newline . $method . $newline . $url . $newline . $bodyString;
            $signature = $this->hmac($this->encode($payload), base64_decode($this->secret), 'sha256', 'base64');
            $headers = $this->extend($headers, array(
                'lmts-api-key' => $this->apiKey,
                'lmts-timestamp' => $timestamp,
                'lmts-signature' => $signature,
            ));
        }
        $url = $baseUrl . $url;
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }

    public function handle_errors(int $statusCode, string $statusText, string $url, string $method, array $responseHeaders, string $responseBody, $response, $requestHeaders, $requestBody) {
        /**
         * @ignore
         * maps limitless error responses to ccxt exceptions
         */
        if ($response === null) {
            return null;
        }
        if (($statusCode >= 200) && ($statusCode < 300)) {
            return null;
        }
        $feedback = $this->id . ' ' . $responseBody;
        // the API returns either a string $message or an array of field-validation errors
        $message = $this->safe_string($response, 'message');
        if ($message !== null) {
            $this->throw_exactly_matched_exception($this->exceptions['exact'], $message, $feedback);
        }
        $this->throw_broadly_matched_exception($this->exceptions['broad'], $responseBody, $feedback);
        return null;
    }
}
